import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, Divider } from '@mui/material';
import { ResponsiveChartContainer, LinePlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface MilestoneData {
  currentMilestone: {
    title: string;
    progress: number;
    deadline: string;
  };
  upcomingDeadlines: {
    title: string;
    date: string;
  }[];
  progressTimeline: {
    date: string;
    progress: number;
  }[];
}

export default function Widget() {
  const data = response.data as MilestoneData;
  const { currentMilestone, upcomingDeadlines, progressTimeline } = data;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600}>
              {currentMilestone.title}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Progress: {currentMilestone.progress}%
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Deadline: {new Date(currentMilestone.deadline).toLocaleDateString()}
            </Typography>
          </Box>

          <Divider />

          <Box>
            <Typography variant="body2" fontWeight={600} sx={{ mb: 1 }}>
              Upcoming Deadlines
            </Typography>
            <Stack spacing={0.5}>
              {upcomingDeadlines.map((deadline) => (
                <Typography key={deadline.title} variant="body2" color="text.secondary">
                  {deadline.title}: {new Date(deadline.date).toLocaleDateString()}
                </Typography>
              ))}
            </Stack>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'line',
                  data: progressTimeline.map((item) => item.progress),
                  color: '#3B82F6',
                  curve: 'linear',
                },
              ]}
              xAxis={[
                {
                  scaleType: 'band',
                  data: progressTimeline.map((item) => new Date(item.date).toLocaleDateString()),
                  id: 'dates',
                },
              ]}
              yAxis={[{ id: 'progress' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <LinePlot />
              </g>
              <ChartsXAxis
                axisId="dates"
                tickLabelStyle={{ fontSize: 10, fill: '#6B7280' }}
              />
              <ChartsYAxis
                axisId="progress"
                tickLabelStyle={{ fontSize: 10, fill: '#6B7280' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
